import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class InsuranceSoapClient:
    """SOAP client for interacting with a third-party insurance service."""

    def __init__(self, wsdl_url, timeout=30):
        """
        Initialize the SOAP client.

        Args:
            wsdl_url: URL to the WSDL of the insurance service
            timeout: Request timeout in seconds
        """
        self.wsdl_url = wsdl_url
        self.history = HistoryPlugin()

        # Configure session with timeout
        session = Session()
        session.timeout = timeout

        # Configure transport
        transport = Transport(session=session, timeout=timeout)

        # Configure zeep settings
        settings = Settings(
            strict=False,
            xml_huge_tree=True
        )

        try:
            self.client = Client(
                wsdl=self.wsdl_url,
                transport=transport,
                settings=settings,
                plugins=[self.history]
            )
            logger.info(f"SOAP client initialized with WSDL: {wsdl_url}")
        except Exception as e:
            logger.error(f"Failed to initialize SOAP client: {e}")
            raise

    def _validate_policy_number(self, policy_number):
        """Validate policy number format."""
        if not policy_number:
            raise ValueError("Policy number cannot be empty")
        # Allow only alphanumeric characters and hyphens
        cleaned = policy_number.strip()
        if not all(c.isalnum() or c == '-' for c in cleaned):
            raise ValueError("Policy number must contain only alphanumeric characters and hyphens")
        if len(cleaned) > 50:
            raise ValueError("Policy number exceeds maximum length of 50 characters")
        return cleaned

    def _validate_customer_name(self, customer_name):
        """Validate customer name."""
        if not customer_name:
            raise ValueError("Customer name cannot be empty")
        cleaned = customer_name.strip()
        # Allow only letters, spaces, hyphens, and apostrophes
        if not all(c.isalpha() or c in (" ", "-", "'", ".") for c in cleaned):
            raise ValueError("Customer name contains invalid characters")
        if len(cleaned) > 200:
            raise ValueError("Customer name exceeds maximum length of 200 characters")
        return cleaned

    def lookup_policy(self, policy_number, customer_name):
        """
        Look up an insurance policy by policy number and customer name.

        Args:
            policy_number: The policy number to look up
            customer_name: The customer's name associated with the policy

        Returns:
            dict: Policy details from the insurance service
        """
        # Validate and sanitize inputs
        validated_policy_number = self._validate_policy_number(policy_number)
        validated_customer_name = self._validate_customer_name(customer_name)

        logger.info(f"Looking up policy: {validated_policy_number} for customer: {validated_customer_name}")

        try:
            # Use zeep's type system to build the request properly
            # This uses parameterized binding rather than string interpolation into XML
            response = self.client.service.LookupPolicy(
                PolicyNumber=validated_policy_number,
                CustomerName=validated_customer_name
            )

            logger.info("Policy lookup successful")
            return self._parse_response(response)

        except zeep.exceptions.Fault as fault:
            logger.error(f"SOAP Fault: {fault.message}")
            raise
        except zeep.exceptions.TransportError as te:
            logger.error(f"Transport error: {te}")
            raise
        except Exception as e:
            logger.error(f"Error during policy lookup: {e}")
            raise

    def get_insurance_quote(self, policy_number, customer_name, coverage_type="standard"):
        """
        Get an insurance quote for a customer.

        Args:
            policy_number: The policy number
            customer_name: The customer's name
            coverage_type: Type of coverage (standard, premium, basic)

        Returns:
            dict: Quote details from the insurance service
        """
        # Validate inputs
        validated_policy_number = self._validate_policy_number(policy_number)
        validated_customer_name = self._validate_customer_name(customer_name)

        valid_coverage_types = ("standard", "premium", "basic")
        if coverage_type not in valid_coverage_types:
            raise ValueError(f"Coverage type must be one of: {valid_coverage_types}")

        logger.info(f"Getting quote for policy: {validated_policy_number}, "
                     f"customer: {validated_customer_name}, coverage: {coverage_type}")

        try:
            response = self.client.service.GetInsuranceQuote(
                PolicyNumber=validated_policy_number,
                CustomerName=validated_customer_name,
                CoverageType=coverage_type
            )

            logger.info("Quote retrieval successful")
            return self._parse_response(response)

        except zeep.exceptions.Fault as fault:
            logger.error(f"SOAP Fault: {fault.message}")
            raise
        except Exception as e:
            logger.error(f"Error getting insurance quote: {e}")
            raise

    def get_policy_status(self, policy_number):
        """
        Check the status of an insurance policy.

        Args:
            policy_number: The policy number to check

        Returns:
            dict: Policy status information
        """
        validated_policy_number = self._validate_policy_number(policy_number)

        logger.info(f"Checking status for policy: {validated_policy_number}")

        try:
            response = self.client.service.GetPolicyStatus(
                PolicyNumber=validated_policy_number
            )

            logger.info("Policy status check successful")
            return self._parse_response(response)

        except zeep.exceptions.Fault as fault:
            logger.error(f"SOAP Fault: {fault.message}")
            raise
        except Exception as e:
            logger.error(f"Error checking policy status: {e}")
            raise

    def _parse_response(self, response):
        """
        Parse the SOAP response into a dictionary.

        Args:
            response: The zeep response object

        Returns:
            dict: Parsed response data
        """
        if response is None:
            return {"status": "no_data", "message": "No data returned from service"}

        # zeep automatically deserializes SOAP responses
        if hasattr(response, '__dict__'):
            return zeep.helpers.serialize_object(response)

        return {"data": response}

    def get_last_request_xml(self):
        """Get the XML of the last sent request for debugging."""
        try:
            return etree.tostring(
                self.history.last_sent["envelope"],
                pretty_print=True,
                encoding="unicode"
            )
        except (IndexError, KeyError, TypeError):
            return "No request history available"

    def get_last_response_xml(self):
        """Get the XML of the last received response for debugging."""
        try:
            return etree.tostring(
                self.history.last_received["envelope"],
                pretty_print=True,
                encoding="unicode"
            )
        except (IndexError, KeyError, TypeError):
            return "No response history available"

    def list_available_operations(self):
        """List all available SOAP operations from the WSDL."""
        operations = []
        for service in self.client.wsdl.services.values():
            for port in service.ports.values():
                for operation in port.binding._operations.values():
                    operations.append(operation.name)
        return operations


